14	// reviewDispatchRunnerStub is a test stub for agent.AgentRunner that captures
15	// the last RunArgs and returns a canned result.
16	type reviewDispatchRunnerStub struct {
17		result   *agent.Result
18		err      error
19		lastOpts agent.RunArgs
20	}
21	
22	func (r *reviewDispatchRunnerStub) Run(opts agent.RunArgs) (*agent.Result, error) {
23		r.lastOpts = opts
24		return r.result, r.err
25	}
