27	func TestReviewDispatcher_DispatchTurn_RecordsTurn(t *testing.T) {
28		workDir := t.TempDir()
29		store := NewReviewSessionStore(workDir)
30		sessionID := "dispatcher-record-001"
31		session := ReviewSession{
32			ID:           sessionID,
33			ArtifactID:   "art-1",
34			SystemRubric: "review carefully",
35			Status:       "open",
36		}
37		if err := store.Create(session); err != nil {
38			t.Fatalf("Create(): %v", err)
39		}
40	
41		runner := &reviewDispatchRunnerStub{
42			result: &agent.Result{Output: "looks good to me"},
43		}
44		d := &ReviewDispatcher{
45			ProjectRoot: workDir,
46			Store:       store,
47			Runner:      runner,
48		}
49	
50		userTurn := ReviewTurn{Actor: "user", Content: "please review"}
51		got, err := d.DispatchReviewTurn(context.Background(), session, userTurn)
52		if err != nil {
53			t.Fatalf("DispatchReviewTurn(): %v", err)
54		}
55		if got.Actor != "reviewer" {
56			t.Errorf("turn.Actor = %q, want %q", got.Actor, "reviewer")
57		}
58		if got.Content != "looks good to me" {
59			t.Errorf("turn.Content = %q, want %q", got.Content, "looks good to me")
60		}
61	
62		// Verify the turn was appended to turns.jsonl.
63		turnsPath := filepath.Join(workDir, ".ddx", reviewSessionsDirName, sessionID, reviewTurnsName)
64		data, err := os.ReadFile(turnsPath)
65		if err != nil {
66			t.Fatalf("reading turns.jsonl: %v", err)
67		}
68		lines := splitNonEmptyLines(string(data))
69		if len(lines) != 1 {
70			t.Fatalf("turns.jsonl line count = %d, want 1", len(lines))
71		}
72		var recorded ReviewTurn
73		if err := json.Unmarshal([]byte(lines[0]), &recorded); err != nil {
74			t.Fatalf("parse recorded turn: %v", err)
75		}
76		if recorded.Actor != "reviewer" {
77			t.Errorf("recorded turn.Actor = %q, want reviewer", recorded.Actor)
78		}
79		if recorded.Content != "looks good to me" {
80			t.Errorf("recorded turn.Content = %q, want %q", recorded.Content, "looks good to me")
81		}
82	}
