84	// TestReviewDispatcher_NoToolMode_ClaudeHarness verifies that every dispatch
85	// carries agent.PermissionsReadOnlyReviewer in RunArgs.Permissions, which the
86	// claude harness translates into disabled tool use before sending the request.
87	func TestReviewDispatcher_NoToolMode_ClaudeHarness(t *testing.T) {
88		workDir := t.TempDir()
89		store := NewReviewSessionStore(workDir)
90		sessionID := "dispatcher-notool-001"
91		session := ReviewSession{
92			ID:     sessionID,
93			Status: "open",
94		}
95		if err := store.Create(session); err != nil {
96			t.Fatalf("Create(): %v", err)
97		}
98	
99		runner := &reviewDispatchRunnerStub{
100			result: &agent.Result{Output: "review complete"},
101		}
102		d := &ReviewDispatcher{
103			ProjectRoot: workDir,
104			Store:       store,
105			Runner:      runner,
106		}
107	
108		_, err := d.DispatchReviewTurn(context.Background(), session, ReviewTurn{Actor: "user", Content: "check it"})
109		if err != nil {
110			t.Fatalf("DispatchReviewTurn(): %v", err)
111		}
112	
113		if runner.lastOpts.Permissions != agent.PermissionsReadOnlyReviewer {
114			t.Errorf("RunArgs.Permissions = %q, want %q (tool use must be disabled for claude harness)",
115				runner.lastOpts.Permissions, agent.PermissionsReadOnlyReviewer)
116		}
117	}
