119	// TestReview_FullTurnLifecycle exercises the full dispatch-through-recording
120	// path: prompt assembly includes prior turns + new user turn, the reviewer
121	// harness is called, and the resulting turn lands in turns.jsonl.
122	func TestReview_FullTurnLifecycle(t *testing.T) {
123		workDir := t.TempDir()
124		store := NewReviewSessionStore(workDir)
125		sessionID := "dispatcher-lifecycle-001"
126		session := ReviewSession{
127			ID:           sessionID,
128			ArtifactID:   "art-lifecycle",
129			ArtifactSHA:  "sha-lifecycle",
130			SystemRubric: "review the change carefully",
131			TemplateRef:  "template://review/default",
132			PromptRef:    "prompt://review/default",
133			Status:       "open",
134			Turns: []ReviewTurn{
135				{Actor: "user", Content: "initial review request"},
136			},
137		}
138		if err := store.Create(session); err != nil {
139			t.Fatalf("Create(): %v", err)
140		}
141	
142		runner := &reviewDispatchRunnerStub{
143			result: &agent.Result{
144				Output:  "BLOCK: missing tests",
145				CostUSD: 0.05,
146			},
147		}
148		d := &ReviewDispatcher{
149			ProjectRoot: workDir,
150			Store:       store,
151			Runner:      runner,
152		}
153	
154		userTurn := ReviewTurn{Actor: "user", Content: "here are the changes"}
155		reviewerTurn, err := d.DispatchReviewTurn(context.Background(), session, userTurn)
156		if err != nil {
157			t.Fatalf("DispatchReviewTurn(): %v", err)
158		}
159	
160		if reviewerTurn.Actor != "reviewer" {
161			t.Errorf("reviewerTurn.Actor = %q, want reviewer", reviewerTurn.Actor)
162		}
163		if !strings.Contains(reviewerTurn.Content, "BLOCK") {
164			t.Errorf("reviewerTurn.Content = %q, expected to contain BLOCK", reviewerTurn.Content)
165		}
166		if reviewerTurn.CostUSD != 0.05 {
167			t.Errorf("reviewerTurn.CostUSD = %v, want 0.05", reviewerTurn.CostUSD)
168		}
169	
170		// Verify the turn was recorded in turns.jsonl.
171		turnsPath := filepath.Join(workDir, ".ddx", reviewSessionsDirName, sessionID, reviewTurnsName)
172		data, err := os.ReadFile(turnsPath)
173		if err != nil {
174			t.Fatalf("reading turns.jsonl: %v", err)
175		}
176		lines := splitNonEmptyLines(string(data))
177		if len(lines) != 1 {
178			t.Fatalf("turns.jsonl line count = %d, want 1 (reviewer turn only)", len(lines))
179		}
180		var recorded ReviewTurn
181		if err := json.Unmarshal([]byte(lines[0]), &recorded); err != nil {
182			t.Fatalf("parse recorded turn: %v", err)
183		}
184		if recorded.Actor != "reviewer" {
185			t.Errorf("recorded turn.Actor = %q, want reviewer", recorded.Actor)
186		}
187	
188		// Verify the assembled prompt contains both the prior turn and the new turn.
189		if !strings.Contains(runner.lastOpts.Prompt, "initial review request") {
190			t.Errorf("prompt should contain prior session turn content")
191		}
192		if !strings.Contains(runner.lastOpts.Prompt, "here are the changes") {
193			t.Errorf("prompt should contain the incoming user turn content")
194		}
195	}
